const onPaste = (event: React.ClipboardEvent<any>) => {
  event.preventDefault();
  const pastedValue = event.clipboardData.getData('text');
  const parsedTime = (pasteSplit || getParsedTime)({ time: pastedValue, format, amPmLabels });
  const timeString = getTimeString({ ...parsedTime, format, withSeconds, amPmLabels });
  if (timeString.valid) {
    acceptChange.current = false;
    const defaultMax = type === 'duration' ? '9999:59:59' : '23:59:59';
    const clamped = clampTime(timeString.value, min || '00:00:00', max || defaultMax);
    onChange?.(clamped.timeString);
    setHours(parsedTime.hours);
    setMinutes(parsedTime.minutes);
    setSeconds(parsedTime.seconds);
    setAmPm(parsedTime.amPm);
  }
};

const getControlProps = (date: DateStringValue) => {
  if (type === 'range') {
    return {
      selected: _value.some(
        (selection: DateStringValue) => selection && dayjs(selection).isSame(date, level)
      ),
      inRange: isDateInRange(date),
      firstInRange: isFirstInRange(date),
      lastInRange: isLastInRange(date),
      'data-autofocus': (!!_value[0] && dayjs(_value[0]).isSame(date, level)) || undefined,
    };
  }

  if (type === 'multiple') {
    return {
      selected: _value.some(
        (selection: DateStringValue) => selection && dayjs(selection).isSame(date, level)
      ),
      'data-autofocus': (!!_value[0] && dayjs(_value[0]).isSame(date, level)) || undefined,
    };
  }

  const selected = dayjs(_value).isSame(date, level);
  return { selected, 'data-autofocus': selected || undefined };
};

